// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.junit.jupiter.api.Test;

class JoinPlanEnumeratorTest {

	private static final String DP_ENABLED_PROPERTY = "rdf4j.optimizer.dp.enabled";
	private static final String BEAM_ENABLED_PROPERTY = "rdf4j.optimizer.beam.enabled";
	private static final String DP_MAX_TERMS_PROPERTY = "rdf4j.optimizer.dp.maxTerms";

	@Test
	void exactDpKeepsDisconnectedPatternLast() {
		StatementPattern disconnected = pattern("urn:test:cross", "x1", "o1");
		StatementPattern left = pattern("urn:test:left", "join", "o2");
		StatementPattern right = pattern("urn:test:right", "join", "o3");

		JoinPlanEnumerator enumerator = new JoinPlanEnumerator(
				new FixedStatistics(Map.of(
						"urn:test:cross", estimate(1.0),
						"urn:test:left", estimate(8.0),
						"urn:test:right", estimate(9.0))),
				new JoinCostModel(), 12, 8, 0.25);

		List<TupleExpr> ordered = enumerator.orderJoinArgs(List.of(disconnected, left, right));

		assertEquals(disconnected, ordered.get(2));
	}

	@Test
	void beamFallbackDelaysDisconnectedPattern() {
		StatementPattern disconnected = pattern("urn:test:cross", "x1", "o1");
		StatementPattern left = pattern("urn:test:left", "join1", "o2");
		StatementPattern middle = pattern("urn:test:middle", "join1", "join2");
		StatementPattern right = pattern("urn:test:right", "join2", "o4");

		JoinPlanEnumerator enumerator = new JoinPlanEnumerator(
				new FixedStatistics(Map.of(
						"urn:test:cross", estimate(18.0),
						"urn:test:left", estimate(10.0),
						"urn:test:middle", estimate(12.0),
						"urn:test:right", estimate(11.0))),
				new JoinCostModel(), 2, 3, 0.25);

		List<TupleExpr> ordered = enumerator.orderJoinArgs(List.of(disconnected, left, middle, right));

		assertTrue(ordered.indexOf(disconnected) >= 2,
				"beam fallback should keep disconnected patterns out of the early prefix");
	}

	@Test
	void beamFallbackSupportsMoreThanThirtyTwoJoinArgs() {
		List<TupleExpr> joinArgs = new ArrayList<>();
		for (int i = 0; i < 40; i++) {
			joinArgs.add(pattern("urn:test:p" + i, "v" + i, "v" + (i + 1)));
		}

		JoinPlanEnumerator enumerator = new JoinPlanEnumerator(new EvaluationStatistics(), new JoinCostModel(), 2, 8,
				0.25);
		List<TupleExpr> ordered = enumerator.orderJoinArgs(joinArgs);

		assertEquals(joinArgs.size(), ordered.size());
		assertEquals(new HashSet<>(joinArgs), new HashSet<>(ordered));
	}

	@Test
	void disablingDpAndBeamKeepsOriginalOrder() {
		StatementPattern disconnected = pattern("urn:test:cross", "x1", "o1");
		StatementPattern left = pattern("urn:test:left", "join", "o2");
		StatementPattern right = pattern("urn:test:right", "join", "o3");

		withProperty(DP_ENABLED_PROPERTY, "false", () -> withProperty(BEAM_ENABLED_PROPERTY, "false", () -> {
			JoinPlanEnumerator enumerator = new JoinPlanEnumerator(
					new FixedStatistics(Map.of(
							"urn:test:cross", estimate(1.0),
							"urn:test:left", estimate(8.0),
							"urn:test:right", estimate(9.0))),
					new JoinCostModel());

			List<TupleExpr> ordered = enumerator.orderJoinArgs(List.of(disconnected, left, right));
			assertEquals(List.of(disconnected, left, right), ordered);
		}));
	}

	@Test
	void disablingBeamKeepsOriginalOrderForLargeJoinGroup() {
		StatementPattern disconnected = pattern("urn:test:cross", "x1", "o1");
		StatementPattern left = pattern("urn:test:left", "join1", "o2");
		StatementPattern middle = pattern("urn:test:middle", "join1", "join2");
		StatementPattern right = pattern("urn:test:right", "join2", "o4");

		withProperty(DP_MAX_TERMS_PROPERTY, "2", () -> withProperty(BEAM_ENABLED_PROPERTY, "false", () -> {
			JoinPlanEnumerator enumerator = new JoinPlanEnumerator(
					new FixedStatistics(Map.of(
							"urn:test:cross", estimate(18.0),
							"urn:test:left", estimate(10.0),
							"urn:test:middle", estimate(12.0),
							"urn:test:right", estimate(11.0))),
					new JoinCostModel());

			List<TupleExpr> ordered = enumerator.orderJoinArgs(List.of(disconnected, left, middle, right));
			assertEquals(List.of(disconnected, left, middle, right), ordered);
		}));
	}

	private static StatementPattern pattern(String predicateIri, String subjectVarName, String objectVarName) {
		Value predicateValue = SimpleValueFactory.getInstance().createIRI(predicateIri);
		return new StatementPattern(new Var(subjectVarName), new Var("p", predicateValue), new Var(objectVarName));
	}

	private static EvaluationStatistics.CardinalityEstimate estimate(double estimate) {
		return new EvaluationStatistics.CardinalityEstimate(estimate, estimate * 0.8, estimate * 1.2, 0.8, "test");
	}

	private static void withProperty(String property, String value, Runnable runnable) {
		String previous = System.getProperty(property);
		try {
			if (value == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, value);
			}
			runnable.run();
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	private static final class FixedStatistics extends EvaluationStatistics {
		private final Map<String, CardinalityEstimate> perPredicate;

		private FixedStatistics(Map<String, CardinalityEstimate> perPredicate) {
			this.perPredicate = perPredicate;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			return getCardinalityEstimate(expr).estimate;
		}

		@Override
		public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Value predicateValue = ((StatementPattern) expr).getPredicateVar().getValue();
				if (predicateValue != null) {
					CardinalityEstimate estimate = perPredicate.get(predicateValue.stringValue());
					if (estimate != null) {
						return estimate;
					}
				}
			}
			return createCardinalityEstimate(100.0, 50.0, 200.0, 0.5, "fallback");
		}
	}
}
